import{_ as a,o as n,c as t,a4 as e}from"./chunks/framework._in6GHBg.js";const g=JSON.parse('{"title":"电磁学详解","description":"","frontmatter":{},"headers":[],"relativePath":"physics/electromagnetism.md","filePath":"physics/electromagnetism.md"}'),p={name:"physics/electromagnetism.md"};function l(i,s,o,c,r,d){return n(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="电磁学详解" tabindex="-1">电磁学详解 <a class="header-anchor" href="#电磁学详解" aria-label="Permalink to &quot;电磁学详解&quot;">​</a></h1><p><strong>类别六：电磁学</strong><br><strong>学习时机</strong>：高二全年<br><strong>核心能力</strong>：场的概念、电磁综合、现代应用</p><hr><h2 id="类别概述" tabindex="-1">类别概述 <a class="header-anchor" href="#类别概述" aria-label="Permalink to &quot;类别概述&quot;">​</a></h2><p>电磁学是高中物理的压轴板块，知识密集、综合性强、难度大。从静电场到电磁感应，构建了完整的电磁理论体系。</p><p><strong>五个模型的递进关系</strong>：</p><ul><li><strong>模型21 电场粒子运动</strong>：电场对带电粒子的作用（类平抛）</li><li><strong>模型22 磁场粒子运动</strong>：磁场对运动电荷的作用（圆周）</li><li><strong>模型23 复合场</strong>：电场+磁场+重力场的综合（最复杂）</li><li><strong>模型24 单杆切割</strong>：电磁感应基础（单导体棒）</li><li><strong>模型25 双杆切割</strong>：电磁感应进阶（双导体棒+动量）</li></ul><p><strong>核心思想</strong>：</p><ul><li>场是物质存在的一种形式（电场、磁场）</li><li>电荷在电场中受力，运动电荷在磁场中受力</li><li>变化的磁场产生电场（电磁感应）</li></ul><hr><h2 id="模型21-电场中带电粒子运动" tabindex="-1">模型21：电场中带电粒子运动 <a class="header-anchor" href="#模型21-电场中带电粒子运动" aria-label="Permalink to &quot;模型21：电场中带电粒子运动&quot;">​</a></h2><h3 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h3><p><strong>电场强度</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>定义：E = F/q（描述电场的力的性质）</span></span>
<span class="line"><span>点电荷：E = kQ/r²</span></span>
<span class="line"><span>匀强电场：E = U/d</span></span></code></pre></div><p><strong>电势与电势能</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>电势：φ = Ep/q（描述电场的能的性质）</span></span>
<span class="line"><span>电势能：Ep = qφ</span></span>
<span class="line"><span>电势差：UAB = φA - φB = WAB/q</span></span></code></pre></div><p><strong>电场力做功</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WAB = qUAB = q(φA - φB) = -ΔEp</span></span></code></pre></div><blockquote><p>与路径无关，只与始末位置有关</p></blockquote><p><strong>带电粒子在电场中的加速</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>qU = ½mv² - ½mv₀²（动能定理）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>初速为0时：v = √(2qU/m)</span></span></code></pre></div><p><strong>带电粒子在电场中的偏转</strong>（类平抛）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>水平：x = v₀t（匀速）</span></span>
<span class="line"><span>竖直：y = ½at²，a = qE/m = qU/md</span></span>
<span class="line"><span></span></span>
<span class="line"><span>偏转角：tanθ = vy/vx = qUL/mdv₀²</span></span></code></pre></div><h3 id="典型应用" tabindex="-1">典型应用 <a class="header-anchor" href="#典型应用" aria-label="Permalink to &quot;典型应用&quot;">​</a></h3><p><strong>应用1：示波器原理</strong></p><p>电子先经加速电场获得速度，再经偏转电场偏转，最后打在荧光屏上。</p><p><strong>应用2：质谱仪</strong></p><p>先用电场加速，再用磁场偏转，根据偏转半径测量比荷q/m。</p><h3 id="典型例题" tabindex="-1">典型例题 <a class="header-anchor" href="#典型例题" aria-label="Permalink to &quot;典型例题&quot;">​</a></h3><p><strong>【例题】带电粒子在电场中的偏转</strong></p><p>质量为m、电荷量为+q的粒子，以初速度v₀垂直射入宽度为L、场强为E的匀强电场，求： (1) 粒子在电场中运动的时间 (2) 粒子的偏转位移 (3) 粒子的偏转角</p><p><strong>解析</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(1) 水平匀速：t = L/v₀</span></span>
<span class="line"><span></span></span>
<span class="line"><span>(2) 竖直匀加速：</span></span>
<span class="line"><span>    a = qE/m</span></span>
<span class="line"><span>    y = ½at² = ½·(qE/m)·(L/v₀)² = qEL²/(2mv₀²)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>(3) 偏转角：</span></span>
<span class="line"><span>    vy = at = qEL/(mv₀)</span></span>
<span class="line"><span>    tanθ = vy/v₀ = qEL/(mv₀²)</span></span></code></pre></div><hr><h2 id="模型22-磁场中带电粒子运动" tabindex="-1">模型22：磁场中带电粒子运动 <a class="header-anchor" href="#模型22-磁场中带电粒子运动" aria-label="Permalink to &quot;模型22：磁场中带电粒子运动&quot;">​</a></h2><h3 id="核心概念-1" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念-1" aria-label="Permalink to &quot;核心概念&quot;">​</a></h3><p><strong>洛伦兹力</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>F = qvBsinθ</span></span>
<span class="line"><span></span></span>
<span class="line"><span>θ = 0°或180°：F = 0（平行磁场，直线运动）</span></span>
<span class="line"><span>θ = 90°：F = qvB（垂直磁场，圆周运动）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>方向：左手定则</span></span>
<span class="line"><span>- 正电荷：四指v，磁感线穿掌心，拇指F</span></span>
<span class="line"><span>- 负电荷：四指与v反向</span></span></code></pre></div><p><strong>重要特点</strong>：洛伦兹力始终垂直于速度，<strong>不做功</strong>，只改变速度方向。</p><p><strong>匀速圆周运动公式</strong>（垂直入射）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>洛伦兹力 = 向心力</span></span>
<span class="line"><span>qvB = mv²/r</span></span>
<span class="line"><span></span></span>
<span class="line"><span>半径：r = mv/qB</span></span>
<span class="line"><span>周期：T = 2πm/qB（与速度无关！）</span></span>
<span class="line"><span>运动时间：t = θm/qB（θ为圆心角，弧度）</span></span></code></pre></div><h3 id="几何分析关键" tabindex="-1">几何分析关键 <a class="header-anchor" href="#几何分析关键" aria-label="Permalink to &quot;几何分析关键&quot;">​</a></h3><p><strong>找圆心方法</strong>：</p><ol><li>速度垂线交点</li><li>弦的垂直平分线</li><li>入射点和出射点连线（弦）</li></ol><p><strong>常用几何关系</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>弦长：L = 2r·sin(θ/2)</span></span>
<span class="line"><span>弧长：s = rθ</span></span>
<span class="line"><span>偏转角 = 圆心角 = 2×弦切角</span></span></code></pre></div><h3 id="典型边界问题" tabindex="-1">典型边界问题 <a class="header-anchor" href="#典型边界问题" aria-label="Permalink to &quot;典型边界问题&quot;">​</a></h3><p><strong>直线边界</strong>：</p><ul><li>入射角 = 出射角（对称）</li><li>偏转角 = 2×入射角</li></ul><p><strong>圆形磁场区域</strong>：</p><ul><li>指向圆心入射，背离圆心出射</li><li>四边形：入射点、出射点、磁场圆心、轨迹圆心</li></ul><p><strong>临界问题</strong>：</p><ul><li>刚好射出、刚好不射出</li><li>找与边界相切的临界轨迹</li></ul><h3 id="典型例题-1" tabindex="-1">典型例题 <a class="header-anchor" href="#典型例题-1" aria-label="Permalink to &quot;典型例题&quot;">​</a></h3><p><strong>【例题】磁场中的圆周运动</strong></p><p>质量为m、电荷量为+q的粒子，以速度v垂直射入宽度为d的匀强磁场（磁感应强度为B），粒子从另一侧射出，速度偏转了60°，求： (1) 粒子运动的半径 (2) 粒子在磁场中运动的时间</p><p><strong>解析</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(1) 几何关系：</span></span>
<span class="line"><span>    由图可知，r·sin60° = d</span></span>
<span class="line"><span>    r = d/sin60° = 2d/√3 = 2√3d/3</span></span>
<span class="line"><span></span></span>
<span class="line"><span>(2) 运动时间：</span></span>
<span class="line"><span>    t = θm/qB = (π/3)m/qB = πm/(3qB)</span></span></code></pre></div><hr><h2 id="模型23-复合场问题" tabindex="-1">模型23：复合场问题 <a class="header-anchor" href="#模型23-复合场问题" aria-label="Permalink to &quot;模型23：复合场问题&quot;">​</a></h2><h3 id="核心模型" tabindex="-1">核心模型 <a class="header-anchor" href="#核心模型" aria-label="Permalink to &quot;核心模型&quot;">​</a></h3><p><strong>复合场类型</strong>：</p><ul><li>电场+磁场（速度选择器、质谱仪、回旋加速器）</li><li>电场+重力场（带电微粒）</li><li>电场+磁场+重力场（最复杂）</li></ul><p><strong>速度选择器原理</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>电场力与洛伦兹力平衡</span></span>
<span class="line"><span>qE = qvB</span></span>
<span class="line"><span>v = E/B</span></span>
<span class="line"><span></span></span>
<span class="line"><span>只有速度为E/B的粒子能直线通过</span></span></code></pre></div><p><strong>质谱仪原理</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>先加速：qU = ½mv² → v = √(2qU/m)</span></span>
<span class="line"><span>再偏转：r = mv/qB = √(2mU/q)/B</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不同质量的粒子偏转半径不同，实现分离</span></span></code></pre></div><h3 id="解题步骤" tabindex="-1">解题步骤 <a class="header-anchor" href="#解题步骤" aria-label="Permalink to &quot;解题步骤&quot;">​</a></h3><p><strong>复合场问题标准解法</strong>：</p><ol><li><strong>分区域分析</strong>：电场区域、磁场区域分别处理</li><li><strong>找衔接点</strong>：交界面处的速度（大小和方向）是关键</li><li><strong>用对公式</strong>： <ul><li>电场：类平抛方法</li><li>磁场：圆周运动几何</li></ul></li><li><strong>几何关系</strong>：画标准图，标圆心、半径、角度</li></ol><h3 id="典型例题-2" tabindex="-1">典型例题 <a class="header-anchor" href="#典型例题-2" aria-label="Permalink to &quot;典型例题&quot;">​</a></h3><p>见【套路模板/复合场问题套路.md】，含完整步骤详解。</p><hr><h2 id="模型24-电磁感应单杆切割" tabindex="-1">模型24：电磁感应单杆切割 <a class="header-anchor" href="#模型24-电磁感应单杆切割" aria-label="Permalink to &quot;模型24：电磁感应单杆切割&quot;">​</a></h2><h3 id="核心概念-2" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念-2" aria-label="Permalink to &quot;核心概念&quot;">​</a></h3><p><strong>感应电动势</strong>（动生）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ε = BLv</span></span>
<span class="line"><span></span></span>
<span class="line"><span>B：磁感应强度</span></span>
<span class="line"><span>L：有效切割长度（垂直于v和B）</span></span>
<span class="line"><span>v：导体棒速度（垂直于B）</span></span></code></pre></div><p><strong>感应电流</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I = ε/R = BLv/R</span></span>
<span class="line"><span></span></span>
<span class="line"><span>R为回路总电阻</span></span></code></pre></div><p><strong>安培力</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>F安 = BIL = B²L²v/R</span></span>
<span class="line"><span></span></span>
<span class="line"><span>方向：阻碍相对运动（楞次定律）</span></span></code></pre></div><h3 id="运动类型分析" tabindex="-1">运动类型分析 <a class="header-anchor" href="#运动类型分析" aria-label="Permalink to &quot;运动类型分析&quot;">​</a></h3><p><strong>情况1：有初速度，无外力</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>只有安培力（阻力）</span></span>
<span class="line"><span>-B²L²v/R = ma = m(dv/dt)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>变减速运动，最终v→0</span></span></code></pre></div><p><strong>情况2：恒定外力F</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>F - B²L²v/R = ma</span></span>
<span class="line"><span></span></span>
<span class="line"><span>随着v增大，安培力增大，a减小</span></span>
<span class="line"><span>最终匀速：F = B²L²vₘ/R</span></span>
<span class="line"><span>最大速度：vₘ = FR/B²L²</span></span></code></pre></div><p><strong>情况3：倾斜导轨，重力分量</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mgsinθ - B²L²v/R = ma</span></span>
<span class="line"><span></span></span>
<span class="line"><span>最终匀速：vₘ = mgRsinθ/B²L²</span></span></code></pre></div><h3 id="能量分析" tabindex="-1">能量分析 <a class="header-anchor" href="#能量分析" aria-label="Permalink to &quot;能量分析&quot;">​</a></h3><p><strong>核心关系</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>外力做功（或重力做功）= 动能变化 + 焦耳热</span></span>
<span class="line"><span></span></span>
<span class="line"><span>或：ΔE机 = Q</span></span></code></pre></div><p><strong>电荷量计算</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>q = I·Δt = ΔΦ/R = BLs/R</span></span>
<span class="line"><span></span></span>
<span class="line"><span>其中s为杆的位移</span></span></code></pre></div><h3 id="典型例题-3" tabindex="-1">典型例题 <a class="header-anchor" href="#典型例题-3" aria-label="Permalink to &quot;典型例题&quot;">​</a></h3><p>见【套路模板/单杆切割模型套路.md】，含完整步骤。</p><hr><h2 id="模型25-电磁感应双杆切割" tabindex="-1">模型25：电磁感应双杆切割 <a class="header-anchor" href="#模型25-电磁感应双杆切割" aria-label="Permalink to &quot;模型25：电磁感应双杆切割&quot;">​</a></h2><h3 id="核心模型-1" tabindex="-1">核心模型 <a class="header-anchor" href="#核心模型-1" aria-label="Permalink to &quot;核心模型&quot;">​</a></h3><p><strong>两杆都切割磁感线</strong>，都产生感应电动势：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ε₁ = BLv₁</span></span>
<span class="line"><span>ε₂ = BLv₂</span></span>
<span class="line"><span></span></span>
<span class="line"><span>回路总电动势：ε = BL(v₁ - v₂) = BL·Δv</span></span></code></pre></div><p><strong>安培力</strong>：两杆串联，电流相同，安培力大小相等、方向相反</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>F安 = BIL = B²L²(v₁-v₂)/R</span></span></code></pre></div><h3 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h3><p><strong>动量守恒</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>两杆受的安培力是作用力反作用力，系统合外力为零</span></span>
<span class="line"><span>→ 系统动量守恒！</span></span>
<span class="line"><span></span></span>
<span class="line"><span>m₁v₁ + m₂v₂ = (m₁+m₂)v共</span></span></code></pre></div><p><strong>最终状态</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>共速时：v₁ = v₂ = v共</span></span>
<span class="line"><span>无相对运动 → 无感应电流 → 无安培力</span></span>
<span class="line"><span>→ 匀速运动</span></span></code></pre></div><p><strong>热量计算</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Q = ΔEk = ½m₁v₁² + ½m₂v₂² - ½(m₁+m₂)v共²</span></span>
<span class="line"><span></span></span>
<span class="line"><span>或：Q = ½μ(Δv)²，其中μ = m₁m₂/(m₁+m₂)（折合质量）</span></span></code></pre></div><h3 id="典型例题-4" tabindex="-1">典型例题 <a class="header-anchor" href="#典型例题-4" aria-label="Permalink to &quot;典型例题&quot;">​</a></h3><p>见【套路模板/双杆切割模型套路.md】，含完整步骤。</p><hr><h2 id="类别总结" tabindex="-1">类别总结 <a class="header-anchor" href="#类别总结" aria-label="Permalink to &quot;类别总结&quot;">​</a></h2><p><strong>电磁学五类问题对比</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">模型</th><th style="text-align:center;">场环境</th><th style="text-align:center;">运动类型</th><th style="text-align:center;">核心公式</th><th style="text-align:center;">难度</th></tr></thead><tbody><tr><td style="text-align:center;">电场粒子</td><td style="text-align:center;">匀强电场</td><td style="text-align:center;">类平抛</td><td style="text-align:center;">y = qEL²/(2mdv₀²)</td><td style="text-align:center;">⭐⭐⭐</td></tr><tr><td style="text-align:center;">磁场粒子</td><td style="text-align:center;">匀强磁场</td><td style="text-align:center;">圆周</td><td style="text-align:center;">r = mv/qB</td><td style="text-align:center;">⭐⭐⭐⭐</td></tr><tr><td style="text-align:center;">复合场</td><td style="text-align:center;">E+B(+g)</td><td style="text-align:center;">分段</td><td style="text-align:center;">衔接点速度传递</td><td style="text-align:center;">⭐⭐⭐⭐⭐</td></tr><tr><td style="text-align:center;">单杆切割</td><td style="text-align:center;">磁场</td><td style="text-align:center;">变加速</td><td style="text-align:center;">vₘ = FR/B²L²</td><td style="text-align:center;">⭐⭐⭐⭐</td></tr><tr><td style="text-align:center;">双杆切割</td><td style="text-align:center;">磁场</td><td style="text-align:center;">动量守恒</td><td style="text-align:center;">v共 = (m₁v₁+m₂v₂)/(m₁+m₂)</td><td style="text-align:center;">⭐⭐⭐⭐⭐</td></tr></tbody></table><p><strong>高频考点</strong>：</p><ol><li>带电粒子在电场中的偏转（示波器、类平抛）</li><li>带电粒子在磁场中的圆周运动（找圆心、几何关系）</li><li>速度选择器、质谱仪、回旋加速器（复合场应用）</li><li>单杆切割的最大速度、电荷量计算</li><li>双杆切割的动量守恒、热量计算</li></ol><p><strong>与大学物理衔接</strong>：</p><ul><li>麦克斯韦方程组</li><li>电磁场理论</li><li>电磁波</li></ul><h3 id="faq小节" tabindex="-1">FAQ小节 <a class="header-anchor" href="#faq小节" aria-label="Permalink to &quot;FAQ小节&quot;">​</a></h3><p><strong>Q1：电场力和洛伦兹力有什么区别？</strong></p><blockquote><ul><li>电场力：对静止和运动电荷都作用，F = qE，方向与E同向或反向</li><li>洛伦兹力：只对运动电荷作用，F = qvB，方向垂直于v和B所在平面</li><li>电场力可以做功，洛伦兹力永不做功</li></ul></blockquote><p><strong>Q2：为什么双杆最终速度相同？</strong></p><blockquote><p>因为两杆受的安培力大小相等、方向相反（作用力反作用力）。如果v₁ &gt; v₂，感应电流产生安培力会减速v₁、加速v₂，直到v₁ = v₂，此时无相对运动、无感应电流、无安培力，两杆匀速运动。</p></blockquote><p><strong>Q3：单杆切割中为什么安培力总是阻碍运动？</strong>&gt; 楞次定律：感应电流的磁场总是阻碍引起感应电流的磁通量变化。当杆运动时，磁通量变化，感应电流产生的安培力必然阻碍这个运动（来拒去留）。</p><p><strong>Q4：复合场问题为什么关键是找衔接点？</strong>&gt; 因为粒子在电场和磁场中的运动规律完全不同（类平抛 vs 圆周）。衔接点（交界面）的速度大小和方向，是磁场段分析的初始条件，必须正确传递。</p><hr><p><strong>学习建议</strong>：</p><ol><li>先逐个攻克单个场（纯电场、纯磁场）</li><li>再练习电场+磁场复合（速度选择器、质谱仪）</li><li>最后攻克电磁感应（单杆→双杆）</li><li>重视几何作图，磁场问题无图不做题</li></ol>`,129)])])}const u=a(p,[["render",l]]);export{g as __pageData,u as default};
